const proximity = inputs.proximityToSource;
const waterQuality = inputs.waterQualityIndex;
const duration = inputs.exposureDurationYears;
const vulnerability = inputs.individualVulnerabilityScore;
const contaminantType = inputs.primaryContaminantType.toLowerCase();
const frequency = inputs.frequencyOfExposure;

// Input validation and clamping
const safeProximity = Math.max(0.01, proximity); // Ensure not zero or negative
const safeWaterQuality = Math.min(100, Math.max(0, waterQuality)); // Clamp 0-100
const safeDuration = Math.max(0, duration); // Ensure non-negative
const safeVulnerability = Math.min(5, Math.max(1, vulnerability)); // Clamp 1-5
const safeFrequency = Math.max(0, frequency); // Ensure non-negative

// 1. Calculate Proximity Risk Factor (inverse relationship, higher score for closer proximity)
// Score range: 0 to MAX_PROXIMITY_RISK_SCORE. Decays linearly with distance.
const MAX_PROXIMITY_RISK_SCORE = 80; // Max score for being extremely close
const PROXIMITY_DECAY_RATE = 5; // Score drops 5 points per km
const proximityRisk = Math.max(0, MAX_PROXIMITY_RISK_SCORE - (safeProximity * PROXIMITY_DECAY_RATE));

// 2. Calculate Water Quality Risk Factor (inverse relationship, lower index = higher risk)
// Score range: 0 to 100. Lower water quality index means higher risk.
const waterQualityRisk = (100 - safeWaterQuality);

// 3. Calculate Exposure Duration Risk Factor (direct relationship, longer duration = higher risk)
// Score range: 0 to 100 (capped). 20 years = 100 points.
const durationRisk = Math.min(100, safeDuration * 5);

// 4. Calculate Individual Vulnerability Risk Factor (direct relationship, higher score = higher risk)
// Score range: 20 to 100. (1-5 vulnerability score * 20).
const vulnerabilityRisk = safeVulnerability * 20;

// 5. Calculate Contaminant Type Risk Factor (base risk multiplier)
let contaminantTypeFactor = 1.0; // Default for 'soil-based' or unrecognized
switch (contaminantType) {
    case 'airborne':
        contaminantTypeFactor = 1.3; // Higher base risk for airborne contaminants
        break;
    case 'water-borne':
        contaminantTypeFactor = 1.2; // Moderate base risk for water-borne
        break;
    case 'mixed':
        contaminantTypeFactor = 1.5; // Highest base risk for mixed contamination
        break;
    case 'soil-based':
    default:
        contaminantTypeFactor = 1.0; // Standard for soil-based or undefined
}

// 6. Calculate Frequency of Exposure Risk Factor (direct relationship, higher frequency = higher risk)
// Score range: 0 to 100 (capped). 10 events/week = 100 points.
const frequencyRisk = Math.min(100, safeFrequency * 10);

// Apply weights to individual risk components and sum for the base score
// Weights total 1.0 to ensure balanced contribution.
const WEIGHT_PROXIMITY = 0.20;
const WEIGHT_WATER_QUALITY = 0.25;
const WEIGHT_DURATION = 0.15;
const WEIGHT_VULNERABILITY = 0.20;
const WEIGHT_FREQUENCY = 0.20; // Increased frequency weight

let baseRiskScore = (proximityRisk * WEIGHT_PROXIMITY) +
                    (waterQualityRisk * WEIGHT_WATER_QUALITY) +
                    (durationRisk * WEIGHT_DURATION) +
                    (vulnerabilityRisk * WEIGHT_VULNERABILITY) +
                    (frequencyRisk * WEIGHT_FREQUENCY);

// Apply the contaminant type factor as a multiplier to the base risk score
const finalExposureRiskScore = baseRiskScore * contaminantTypeFactor;

// Determine Risk Category based on the final score
let riskCategory = "Very Low";
if (finalExposureRiskScore > 100) {
    riskCategory = "Low";
}
if (finalExposureRiskScore > 250) {
    riskCategory = "Moderate";
}
if (finalExposureRiskScore > 400) {
    riskCategory = "High";
}
if (finalExposureRiskScore > 600) {
    riskCategory = "Very High";
}

return {
    exposureRiskScore: finalExposureRiskScore,
    riskCategory: riskCategory
};
